const checkpoints = [];
const books = JSON.parse(localStorage.getItem('books') || '[]');
const lists = JSON.parse(localStorage.getItem('library_lists') || '[]');
const items = JSON.parse(localStorage.getItem('library_list_items') || '[]');
// Find all qualifying fantasy novels under $18
const qualifyingFantasy = books.filter(b => b && b.genre === 'fantasy' && b.work_type === 'novel' && typeof b.price === 'number' && b.price < 18 && !!b.publication_date);
qualifyingFantasy.sort((a, b) => new Date(b.publication_date) - new Date(a.publication_date));
const newest = qualifyingFantasy[0] || null;
// Identify main reading list(s)
const mainReadingLists = lists.filter(l => l && l.list_type === 'book_reading_list' && (l.is_default || (l.name || '').toLowerCase() === 'main reading list'));
const mainListIds = mainReadingLists.map(l => l.id);
// Any qualifying fantasy novel under $18 added to main reading list?
let anyQualifyingInMain = false;
if (mainListIds.length && qualifyingFantasy.length) {
  anyQualifyingInMain = items.some(it => {
    if (!it || it.item_type !== 'book' || !mainListIds.includes(it.listId)) return false;
    const b = books.find(bb => bb.id === it.bookId);
    return !!b && b.genre === 'fantasy' && b.work_type === 'novel' && typeof b.price === 'number' && b.price < 18;
  });
}
// Specifically, is the newest qualifying fantasy novel on main reading list?
let hasNewestInMain = false;
if (mainListIds.length && newest) {
  hasNewestInMain = items.some(it => it && it.item_type === 'book' && mainListIds.includes(it.listId) && it.bookId === newest.id);
}
// CP1 (0.4): User added at least one qualifying fantasy novel under $18 to the main reading list
checkpoints.push({ passed: anyQualifyingInMain, weight: 0.4 });
// CP2 (0.6): That qualifying book is specifically the newest fantasy novel under $18
checkpoints.push({ passed: hasNewestInMain, weight: 0.6 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const books = JSON.parse(localStorage.getItem('books') || '[]');
const compareSets = JSON.parse(localStorage.getItem('compare_sets') || '[]');
const compareSetItems = JSON.parse(localStorage.getItem('compare_set_items') || '[]');
const lists = JSON.parse(localStorage.getItem('library_lists') || '[]');
const listItems = JSON.parse(localStorage.getItem('library_list_items') || '[]');
let activeCompareSetId = localStorage.getItem('activeCompareSetId') || '';
let compareSet = compareSets.find(cs => cs.id === activeCompareSetId) || null;
if (!compareSet) {
  compareSet = compareSets.find(cs => cs && cs.is_active) || null;
}
let firstTwo = [];
let longerBook = null;
let shorterBook = null;
if (compareSet) {
  const itemsForSet = compareSetItems.filter(it => it && it.compareSetId === compareSet.id);
  const withBooks = itemsForSet.map(it => ({ ...it, book: books.find(b => b.id === it.bookId) || null }));
  const mysteryUnder20 = withBooks.filter(it => {
    const b = it.book;
    return b && b.genre === 'mystery' && b.work_type === 'novel' && typeof b.price === 'number' && b.price < 20;
  });
  mysteryUnder20.sort((a, b) => new Date(a.addedAt || 0) - new Date(b.addedAt || 0));
  firstTwo = mysteryUnder20.slice(0, 2);
  if (firstTwo.length === 2 && firstTwo[0].book && firstTwo[1].book) {
    const b1 = firstTwo[0].book;
    const b2 = firstTwo[1].book;
    if ((b1.page_count || 0) >= (b2.page_count || 0)) {
      longerBook = b1;
      shorterBook = b2;
    } else {
      longerBook = b2;
      shorterBook = b1;
    }
  }
}
// Favorites list(s)
const favoritesLists = lists.filter(l => l && l.list_type === 'favorites');
const favoritesListIds = favoritesLists.map(l => l.id);
const favoriteBookItems = listItems.filter(it => it && it.item_type === 'book' && favoritesListIds.includes(it.listId));
// Books from the first two compare candidates that ended up in favorites
const candidateFavoriteIds = favoriteBookItems.map(it => it.bookId).filter(id => firstTwo.some(c => c.book && c.book.id === id));
const includesLonger = !!(longerBook && candidateFavoriteIds.includes(longerBook.id));
const includesShorter = !!(shorterBook && candidateFavoriteIds.includes(shorterBook.id));
// CP1 (0.4): User has at least two qualifying mystery novels (< $20) in the active compare set
checkpoints.push({ passed: firstTwo.length === 2, weight: 0.4 });
// CP2 (0.3): User favorited at least one of those two compared mystery novels
checkpoints.push({ passed: candidateFavoriteIds.length > 0, weight: 0.3 });
// CP3 (0.3): The favorited choice is only the longer of the two (includes longer, does not include only-shorter)
checkpoints.push({ passed: includesLonger && !includesShorter, weight: 0.3 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const books = JSON.parse(localStorage.getItem('books') || '[]');
const reviews = JSON.parse(localStorage.getItem('reviews') || '[]');
const isShortForm = (b) => !!b && (b.work_type === 'novella' || b.work_type === 'short_story');
// Attach books to reviews
const reviewsWithBook = reviews.map(r => ({ ...r, book: books.find(b => b.id === r.bookId) || null }));
// Candidate reviews: 4-star on a short-form book under 120 pages
const candidateReviews = reviewsWithBook.filter(rb => {
  const b = rb.book;
  return b && rb.rating === 4 && isShortForm(b) && typeof b.page_count === 'number' && b.page_count <= 120;
});
// Of those, require that BEFORE this review, the book's average rating was at least 4.5
const qualifyingRatingReviews = candidateReviews.filter(rb => {
  const prior = reviews.filter(r2 => r2.bookId === rb.bookId && new Date(r2.createdAt || 0) < new Date(rb.createdAt || 0));
  if (!prior.length) return false;
  const sumPrev = prior.reduce((sum, r2) => sum + (typeof r2.rating === 'number' ? r2.rating : 0), 0);
  const avgPrev = sumPrev / prior.length;
  return avgPrev >= 4.5;
});
// Among those, require sufficient comment length
const qualifyingWithComment = qualifyingRatingReviews.filter(rb => typeof rb.body === 'string' && rb.body.trim().length >= 10);
// CP1 (0.6): User left a 4-star review on a qualifying short-form book (under 120 pages, prior avg >= 4.5)
checkpoints.push({ passed: qualifyingRatingReviews.length > 0, weight: 0.6 });
// CP2 (0.4): At least one such review includes a written comment of at least 10 characters
checkpoints.push({ passed: qualifyingWithComment.length > 0, weight: 0.4 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const events = JSON.parse(localStorage.getItem('events') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');
const from = new Date('2025-03-01T00:00:00Z');
const to = new Date('2025-03-31T23:59:59Z');
// All online events in March 2025
const marchOnline = events.filter(ev => {
  if (!ev || ev.event_type !== 'online' || !ev.start_datetime) return false;
  const d = new Date(ev.start_datetime);
  return d >= from && d <= to;
});
marchOnline.sort((a, b) => new Date(a.start_datetime || 0) - new Date(b.start_datetime || 0));
const earliest = marchOnline[0] || null;
// Helper map for event lookup
const eventsById = new Map(events.map(ev => [ev.id, ev]));
// Registrations for any March 2025 online event
const regsForMarchOnline = regs.filter(r => {
  const ev = eventsById.get(r.eventId);
  if (!ev) return false;
  if (ev.event_type !== 'online' || !ev.start_datetime) return false;
  const d = new Date(ev.start_datetime);
  return d >= from && d <= to;
});
// Registrations for the earliest such event
let regsForEarliest = [];
if (earliest) {
  regsForEarliest = regs.filter(r => r.eventId === earliest.id);
}
// Among those, check for correct note
const hasNoteAskAboutSequel = regsForEarliest.some(r => {
  const notes = (r.notes || '').toLowerCase();
  return notes.includes('ask about sequel');
});
// CP1 (0.3): User registered for at least one online event in March 2025
checkpoints.push({ passed: regsForMarchOnline.length > 0, weight: 0.3 });
// CP2 (0.3): User registered specifically for the earliest qualifying March 2025 online event
checkpoints.push({ passed: regsForEarliest.length > 0, weight: 0.3 });
// CP3 (0.4): At least one registration for that earliest event includes a note containing 'Ask about sequel'
checkpoints.push({ passed: hasNoteAskAboutSequel, weight: 0.4 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const books = JSON.parse(localStorage.getItem('books') || '[]');
const bundles = JSON.parse(localStorage.getItem('bundles') || '[]');
const bundleItems = JSON.parse(localStorage.getItem('bundle_items') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
// All qualifying sci-fi eBooks under $10
const sciFiEbooksUnder10 = books.filter(b => b && b.genre === 'science_fiction' && b.format === 'ebook' && typeof b.price === 'number' && b.price < 10);
// Sort by rating descending to get highest-rated
sciFiEbooksUnder10.sort((a, b) => (b.rating || 0) - (a.rating || 0));
const topThree = sciFiEbooksUnder10.slice(0, 3);
const topIds = topThree.map(b => b.id);
let correctBundle = null;
if (topThree.length === 3 && bundles.length) {
  for (const bu of bundles) {
    if (!bu || !bu.id) continue;
    const items = bundleItems.filter(it => it && it.bundleId === bu.id);
    // Unique sci-fi eBooks under $10 actually in this bundle
    const sfIdsInBundleSet = new Set();
    for (const it of items) {
      const bk = books.find(b => b.id === it.bookId);
      if (!bk) continue;
      if (bk.genre === 'science_fiction' && bk.format === 'ebook' && typeof bk.price === 'number' && bk.price < 10) {
        sfIdsInBundleSet.add(bk.id);
      }
    }
    const sfIdsInBundle = Array.from(sfIdsInBundleSet);
    if (sfIdsInBundle.length === topIds.length && topIds.every(id => sfIdsInBundle.includes(id))) {
      correctBundle = bu;
      break;
    }
  }
}
// Did such a bundle get added to the cart?
let bundleInCart = false;
if (correctBundle) {
  bundleInCart = cartItems.some(ci => ci && ci.item_type === 'bundle' && ci.bundleId === correctBundle.id && ci.quantity > 0);
}
// CP1 (0.6): User created a bundle whose sci-fi eBook-under-$10 contents exactly match the top 3 highest-rated options
checkpoints.push({ passed: !!correctBundle, weight: 0.6 });
// CP2 (0.4): That correct bundle has been added to the cart
checkpoints.push({ passed: !!bundleInCart, weight: 0.4 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const messages = JSON.parse(localStorage.getItem('contact_messages') || '[]');
// Messages specifically about bulk orders
const bulkMsgs = messages.filter(m => m && m.topic === 'bulk_orders');
// Among those, look for required subject phrase and message length
const goodBulkMsgs = bulkMsgs.filter(m => {
  const subj = (m.subject || '').toLowerCase();
  const body = (m.message || '');
  const has25 = subj.includes('25');
  const hasPaperback = subj.includes('paperback'); // matches 'paperback' or 'paperbacks'
  const longEnough = body.trim().length >= 20;
  return has25 && hasPaperback && longEnough;
});
// CP1 (0.4): User submitted at least one message with the Bulk Orders topic
checkpoints.push({ passed: bulkMsgs.length > 0, weight: 0.4 });
// CP2 (0.6): At least one Bulk Orders message mentions 25 paperbacks in the subject and has a body of at least 20 characters
checkpoints.push({ passed: goodBulkMsgs.length > 0, weight: 0.6 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const books = JSON.parse(localStorage.getItem('books') || '[]');
const lists = JSON.parse(localStorage.getItem('library_lists') || '[]');
const items = JSON.parse(localStorage.getItem('library_list_items') || '[]');
const from = new Date('2018-01-01T00:00:00Z');
const to = new Date('2020-12-31T23:59:59Z');
// Qualifying YA books
const yaCandidates = books.filter(b => {
  if (!b || b.genre !== 'young_adult' || typeof b.rating !== 'number' || b.rating < 4.0 || !b.publication_date) return false;
  const d = new Date(b.publication_date);
  return d >= from && d <= to;
});
yaCandidates.sort((a, b) => (a.price || 0) - (b.price || 0));
const topTwo = yaCandidates.slice(0, 2);
// Summer 2025 wishlist(s)
const summerLists = lists.filter(l => l && l.list_type === 'book_wishlist' && (l.name || '').toLowerCase() === 'summer 2025');
const summerListIds = summerLists.map(l => l.id);
const summerBookItems = items.filter(it => it && it.item_type === 'book' && summerListIds.includes(it.listId));
let countAdded = 0;
if (topTwo.length === 2 && summerBookItems.length) {
  countAdded = topTwo.filter(b => summerBookItems.some(it => it.bookId === b.id)).length;
}
// CP1 (0.5): At least one of the two cheapest qualifying YA books was added to a 'Summer 2025' wishlist
checkpoints.push({ passed: countAdded >= 1, weight: 0.5 });
// CP2 (0.5): Both of the two cheapest qualifying YA books were added to the 'Summer 2025' wishlist
checkpoints.push({ passed: countAdded >= 2, weight: 0.5 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const posts = JSON.parse(localStorage.getItem('blog_posts') || '[]');
const lists = JSON.parse(localStorage.getItem('library_lists') || '[]');
const items = JSON.parse(localStorage.getItem('library_list_items') || '[]');
// All published posts tagged writing_process with at least 5 comments
const writingProcessWithComments = posts.filter(p => p && p.status === 'published' && Array.isArray(p.tags) && p.tags.includes('writing_process') && typeof p.comment_count === 'number' && p.comment_count >= 5);
writingProcessWithComments.sort((a, b) => new Date(b.published_at || 0) - new Date(a.published_at || 0));
const target = writingProcessWithComments[0] || null;
// Article reading lists
const readingLists = lists.filter(l => l && l.list_type === 'article_reading_list');
const readingListIds = readingLists.map(l => l.id);
const articleItems = items.filter(it => it && it.item_type === 'article' && readingListIds.includes(it.listId));
// Any writing_process post saved at all?
const anyWritingProcessSaved = articleItems.some(it => {
  const p = posts.find(pp => pp.id === it.articleId);
  return p && Array.isArray(p.tags) && p.tags.includes('writing_process');
});
// Specifically, is the target most-recent 5+ comment post saved?
let targetSaved = false;
if (target) {
  targetSaved = articleItems.some(it => it.articleId === target.id);
}
// CP1 (0.4): User saved at least one 'writing_process'-tagged post to an article reading list
checkpoints.push({ passed: anyWritingProcessSaved, weight: 0.4 });
// CP2 (0.6): User saved the most recent 'writing_process' post with 5+ comments to an article reading list
checkpoints.push({ passed: targetSaved, weight: 0.6 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
